  |subst = <includeonly>{{subst:</includeonly><includeonly>substcheck}}</includeonly>
  |type = notice
  |image = [[File:Under construction icon-blue.svg|none|50px|link=]]
  |text = '''This is not a Wikipedia article''': It is one user's '''draft page''' that {{gender:{{ROOTPAGENAME}}|he is|she is|they are}}
 working on. It may be incomplete and/or unreliable.{{#if:{{{page|}}}
   |<br />The current version of this article may be located at [[{{{page}}}]].
  }}<br /><small>{{last edited by}}</small>{{#ifexpr:{{HoursElapsed|{{REVISIONTIMESTAMP}}}}>8760
   |[[Category:Stale userspace drafts]]
  }}<!--COMMENTING OUT ARTICLE WIZARD STUFF FOR THE MOMENT--<br>
----
<span class="plainlinks">Finished? [{{fullurl:{{FULLPAGENAME}}|action=edit&section=new&preload=Template:AFC_submission/Subst&preloadtitle=Request%20review%20at%20%5B%5BWP:AFC%5D%5D}} Submit the page!]</span>}}{{#ifeq:{{{demo|<noinclude>yes</noinclude>}}}|yes|
  |{{#ifeq:{{NAMESPACE}}|Wikipedia talk||{{DMC
   |1=Userspace drafts {{#ifeq:{{{source}}}|ArticleWizard|created via the Article Wizard}}
   |2=from
   |3={{{date|}}}
  }}}}--COMMENTING OUT ARTICLE WIZARD STUFF FOR THE MOMENT-->
 }}
 |={{New unreviewed article
  |subst=<includeonly>{{subst:</includeonly><includeonly>substcheck}}</includeonly>
  |source={{{source|}}}
  |date={{{date|}}}
 }}
 |#default=<includeonly>[[Category:Misplaced userspace drafts]]</includeonly>
}}<noinclude>
{{Documentation}}
</noinclude>

